/* ---------------- Identification du candidat ---------------- */
function IdentityScreen({ onSubmit }) {
  const [nom, setNom] = useState("");
  const [prenom, setPrenom] = useState("");
  const [telephone, setTelephone] = useState("");
  const [error, setError] = useState("");

  const submit = (e) => {
    e.preventDefault();
    if (!nom.trim() || !prenom.trim() || !telephone.trim()) {
      setError("Merci de renseigner votre nom, prénom et numéro de téléphone.");
      return;
    }
    if (telephone.replace(/[^0-9]/g, "").length < 8) {
      setError("Numéro de téléphone invalide.");
      return;
    }
    setError("");
    onSubmit({ nom: nom.trim(), prenom: prenom.trim(), telephone: telephone.trim() });
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, display: "flex", alignItems: "center", justifyContent: "center", padding: 20, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <div style={{ width: "100%", maxWidth: 400 }}>
        <div style={{ marginBottom: 22, display: "flex", justifyContent: "center" }}>
          <Logo />
        </div>
        <form
          onSubmit={submit}
          style={{
            background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 16,
            padding: "28px 24px", boxShadow: "0 1px 3px rgba(15,39,51,0.06)",
          }}
        >
          <TraceDivider />
          <h1 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 19, color: COLORS.ink, margin: "14px 0 4px" }}>Identification du candidat</h1>
          <p style={{ fontSize: 12.5, color: COLORS.inkSoft, margin: "0 0 20px" }}>
            Votre numéro de téléphone identifie votre compte : ressaisissez le même numéro pour retrouver votre historique et votre progression, quel que soit l'appareil utilisé.
          </p>

          <Field label="NOM" value={nom} onChange={setNom} />
          <Field label="PRÉNOM" value={prenom} onChange={setPrenom} style={{ marginTop: 14 }} />
          <Field label="NUMÉRO DE TÉLÉPHONE" value={telephone} onChange={setTelephone} type="tel" style={{ marginTop: 14 }} />

          {error && <div style={{ color: COLORS.red, fontSize: 12.5, marginTop: 10 }}>{error}</div>}

          <button type="submit" style={{ ...primaryBtn, width: "100%", marginTop: 20 }}>
            Continuer
          </button>
        </form>
      </div>
    </div>
  );
}

/* ---------------- Contrôle anti-fraude (photo) ---------------- */
function ProctorCheckScreen({ onReady }) {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);
  const timeoutRef = useRef(null);
  const [status, setStatus] = useState("requesting"); // requesting | live | denied | captured
  const [photo, setPhoto] = useState(null);
  const [flash, setFlash] = useState(false);

  const clearFallbackTimer = () => {
    if (timeoutRef.current) { clearTimeout(timeoutRef.current); timeoutRef.current = null; }
  };

  const startCamera = useCallback(() => {
    setStatus("requesting");
    clearFallbackTimer();
    // si la caméra ne répond pas rapidement (permissions bloquées dans cet aperçu,
    // matériel absent...), on bascule automatiquement sur le mode simulé plutôt
    // que de bloquer l'accès à l'examen
    timeoutRef.current = setTimeout(() => setStatus((s) => (s === "requesting" ? "denied" : s)), 4000);
    navigator.mediaDevices?.getUserMedia?.({ video: { facingMode: "user" }, audio: false })
      .then((s) => {
        clearFallbackTimer();
        streamRef.current = s;
        setStatus("live");
        if (videoRef.current) {
          videoRef.current.srcObject = s;
          videoRef.current.play().catch(() => {});
        }
      })
      .catch(() => { clearFallbackTimer(); setStatus("denied"); });
  }, []);

  useEffect(() => {
    startCamera();
    return () => {
      clearFallbackTimer();
      if (streamRef.current) streamRef.current.getTracks().forEach((t) => t.stop());
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const flashThen = (fn) => {
    setFlash(true);
    setTimeout(() => { setFlash(false); fn(); }, 140);
  };

  const capture = () => {
    if (!videoRef.current || !canvasRef.current) return;
    flashThen(() => {
      const v = videoRef.current, c = canvasRef.current;
      c.width = v.videoWidth || 480;
      c.height = v.videoHeight || 360;
      c.getContext("2d").drawImage(v, 0, 0, c.width, c.height);
      setPhoto(c.toDataURL("image/jpeg", 0.7));
      setStatus("captured");
      if (streamRef.current) streamRef.current.getTracks().forEach((t) => t.stop());
    });
  };

  // formalité : quand la caméra n'est pas accessible, on simule quand même la prise
  // de photo (le contrôle reste un passage obligé avant l'examen) sans jamais
  // enregistrer d'image réelle
  const captureSimulated = () => {
    flashThen(() => {
      const c = canvasRef.current;
      if (c) {
        c.width = 480; c.height = 360;
        const ctx = c.getContext("2d");
        ctx.fillStyle = COLORS.blueDeep;
        ctx.fillRect(0, 0, c.width, c.height);
        ctx.fillStyle = "#ffffff";
        ctx.font = "600 15px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText("Contrôle de présence", c.width / 2, c.height / 2 - 8);
        ctx.font = "400 12px sans-serif";
        ctx.fillText(new Date().toLocaleString("fr-FR"), c.width / 2, c.height / 2 + 14);
        setPhoto(c.toDataURL("image/png"));
      }
      setStatus("captured");
    });
  };

  const retake = () => {
    setPhoto(null);
    startCamera();
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <div style={{ background: COLORS.surface, borderBottom: `1px solid ${COLORS.line}`, padding: "12px 18px" }}>
        <div style={{ maxWidth: 520, margin: "0 auto" }}><Logo /></div>
      </div>
      <div style={{ maxWidth: 520, margin: "0 auto", padding: "26px 18px 60px" }}>
        <div style={{ background: COLORS.amberSoft, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 16, marginBottom: 20 }}>
          <div style={{ fontSize: 12.5, fontWeight: 700, color: COLORS.amber, marginBottom: 6 }}>⚠ Contrôle anti-fraude</div>
          <div style={{ fontSize: 12.5, color: COLORS.ink, lineHeight: 1.6 }}>
            Vous serez régulièrement photographié(e) pendant l'examen afin d'éviter toute tentative de fraude.
            En cas de tentative détectée (changement d'onglet ou mise en arrière-plan de la fenêtre pendant l'épreuve),{" "}
            <b>votre examen s'arrêtera automatiquement</b> et sera enregistré comme non validé.
          </div>
          <div style={{ fontSize: 11.5, color: COLORS.inkSoft, marginTop: 8, fontStyle: "italic" }}>
            Ce contrôle est un simple constat de présence : aucune photo n'est enregistrée ni transmise.
          </div>
        </div>

        <h1 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 19, color: COLORS.ink, marginBottom: 6 }}>Vérification avant l'examen</h1>
        <p style={{ fontSize: 12.5, color: COLORS.inkSoft, marginBottom: 16 }}>
          Installez-vous dans un endroit bien éclairé, cadrez votre visage au centre du cadre et tenez-vous droit, puis prenez votre photo.
        </p>

        <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 16, padding: 18, textAlign: "center" }}>
          <div style={{ position: "relative", width: 260, height: 200, margin: "0 auto", borderRadius: 12, overflow: "hidden", background: COLORS.blueDeep }}>
            {status !== "captured" && status !== "denied" && (
              <video ref={videoRef} muted playsInline style={{ width: "100%", height: "100%", objectFit: "cover", transform: "scaleX(-1)" }} />
            )}
            {status === "captured" && photo && (
              <img src={photo} alt="Photo du candidat" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            )}
            <div style={{ position: "absolute", inset: "14px 58px", border: "2px dashed rgba(255,255,255,0.55)", borderRadius: "50% / 42%", pointerEvents: "none" }} />
            {flash && <div style={{ position: "absolute", inset: 0, background: "white" }} />}
            {status === "denied" && (
              <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", color: "white", fontSize: 11.5, padding: 16, textAlign: "center", gap: 4 }}>
                <span style={{ fontSize: 22 }}>📷</span>
                Caméra indisponible dans cet aperçu.<br />Le contrôle se poursuit en mode simulé.
              </div>
            )}
            {status === "requesting" && (
              <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 11.5 }}>
                Activation de la caméra…
              </div>
            )}
          </div>
          <canvas ref={canvasRef} style={{ display: "none" }} />

          <div style={{ marginTop: 16, display: "flex", gap: 10, justifyContent: "center" }}>
            {status === "live" && <button onClick={capture} style={primaryBtn}>Prendre la photo</button>}
            {status === "denied" && <button onClick={captureSimulated} style={primaryBtn}>Prendre la photo</button>}
            {status === "captured" && <button onClick={retake} style={secondaryBtn}>Reprendre</button>}
          </div>
        </div>

        <button
          onClick={() => onReady(photo)}
          disabled={status === "requesting"}
          style={{ ...primaryBtn, width: "100%", marginTop: 20, background: COLORS.green, opacity: status === "requesting" ? 0.5 : 1 }}
        >
          {status === "captured" ? "Commencer l'examen" : status === "denied" ? "Continuer sans photo" : "Patientez…"}
        </button>
      </div>
    </div>
  );
}

